program LIPDecide;

{$mode objfpc}{$H+}

uses
  SysUtils, Math, Classes;

const
  MYPI = 3.1415926535;

type
  COMPTYPE = (LT, EQ, GT);
  CONNECTORS = (NOTUSED, ORR, ANDD);

var
  X: array[1..100] of real;
  Y: array[1..100] of real;
  NUMPOINTS: integer;

  { Parameters }
  PARAM_LENGTH1: real;
  PARAM_RADIUS1: real;
  PARAM_EPSILON: real;
  PARAM_AREA1: real;
  PARAM_Q_PTS: integer;
  PARAM_QUADS: integer;
  PARAM_DIST: real;
  PARAM_N_PTS: integer;
  PARAM_K_PTS: integer;
  PARAM_A_PTS: integer;
  PARAM_B_PTS: integer;
  PARAM_C_PTS: integer;
  PARAM_D_PTS: integer;
  PARAM_E_PTS: integer;
  PARAM_F_PTS: integer;
  PARAM_G_PTS: integer;
  PARAM_LENGTH2: real;
  PARAM_RADIUS2: real;
  PARAM_AREA2: real;

  LCM: array[1..15, 1..15] of CONNECTORS;
  PUM: array[1..15, 1..15] of boolean;
  CMV: array[1..15] of boolean;
  FUV: array[1..15] of boolean;
  LAUNCH: boolean;

{ REALCOMPARE - from reference implementation }
function REALCOMPARE(A, B: real): COMPTYPE;
var
  scale, eps, diff: real;
begin
  scale := Abs(A);
  if Abs(B) > scale then
    scale := Abs(B);
  if scale = 0.0 then
  begin
    REALCOMPARE := EQ;
    Exit;
  end;

  eps := 0.5e-5 * scale;
  diff := A - B;
  if diff > eps then
    REALCOMPARE := GT
  else if diff < -eps then
    REALCOMPARE := LT
  else
    REALCOMPARE := EQ;
end;

{ Utility: distance between two points }
function PointDist(x1, y1, x2, y2: real): real;
begin
  PointDist := sqrt(sqr(x2 - x1) + sqr(y2 - y1));
end;

{ Utility: triangle area from three points (unsigned) }
function TriangleArea(x1, y1, x2, y2, x3, y3: real): real;
begin
  TriangleArea := abs((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) / 2.0);
end;

{ Utility: determine quadrant of a point (spec rules for tie-breaking) }
function GetQuadrant(px, py: real): integer;
begin
  if (REALCOMPARE(px, 0.0) <> LT) and (REALCOMPARE(py, 0.0) <> LT) then
    GetQuadrant := 1
  else if (REALCOMPARE(px, 0.0) = LT) and (REALCOMPARE(py, 0.0) <> LT) then
    GetQuadrant := 2
  else if (REALCOMPARE(px, 0.0) <> GT) and (REALCOMPARE(py, 0.0) = LT) then
    GetQuadrant := 3
  else
    GetQuadrant := 4;
end;

{ Utility: check if three points can be contained in a circle of given radius }
{ Returns true if they CAN be contained (i.e., the circumscribed circle radius <= r) }
function FitsInCircle(x1, y1, x2, y2, x3, y3: real; r: real): boolean;
var
  a, b, c, area, circumR: real;
  maxSide: real;
begin
  a := PointDist(x1, y1, x2, y2);
  b := PointDist(x2, y2, x3, y3);
  c := PointDist(x1, y1, x3, y3);
  area := TriangleArea(x1, y1, x2, y2, x3, y3);

  { If area is essentially zero, the points are collinear }
  if REALCOMPARE(area, 0.0) = EQ then
  begin
    { For collinear points, the minimum enclosing circle has diameter = max side }
    maxSide := a;
    if REALCOMPARE(b, maxSide) = GT then maxSide := b;
    if REALCOMPARE(c, maxSide) = GT then maxSide := c;
    { Check if maxSide/2 <= r }
    FitsInCircle := (REALCOMPARE(maxSide / 2.0, r) <> GT);
  end
  else
  begin
    { circumradius R = (a*b*c)/(4*area) }
    circumR := (a * b * c) / (4.0 * area);
    { The minimum enclosing circle is either the circumscribed circle or
      determined by the longest side as diameter, whichever is smaller.
      Actually for MEC: if the triangle is obtuse, MEC is the circle with
      diameter = longest side; if acute or right, MEC = circumscribed circle. }

    { Check if triangle is obtuse by comparing a^2+b^2 vs c^2 etc. }
    { Sort sides: find longest }
    maxSide := a;
    if REALCOMPARE(b, maxSide) = GT then maxSide := b;
    if REALCOMPARE(c, maxSide) = GT then maxSide := c;

    { Check obtuse: if maxSide^2 >= other1^2 + other2^2 }
    if REALCOMPARE(sqr(maxSide), sqr(a) + sqr(b) + sqr(c) - sqr(maxSide)) <> LT then
    begin
      { Obtuse or right triangle: MEC diameter = maxSide }
      FitsInCircle := (REALCOMPARE(maxSide / 2.0, r) <> GT);
    end
    else
    begin
      { Acute triangle: MEC = circumscribed circle }
      FitsInCircle := (REALCOMPARE(circumR, r) <> GT);
    end;
  end;
end;

{ Utility: compute angle at vertex (x2,y2) formed by points (x1,y1)-(x2,y2)-(x3,y3) }
{ Returns angle in radians. Returns -1 if undefined (vertex coincides with another point) }
function ComputeAngle(x1, y1, x2, y2, x3, y3: real): real;
var
  dx1, dy1, dx2, dy2: real;
  d1, d2, dot, cross, ang: real;
begin
  dx1 := x1 - x2;
  dy1 := y1 - y2;
  dx2 := x3 - x2;
  dy2 := y3 - y2;
  d1 := sqrt(sqr(dx1) + sqr(dy1));
  d2 := sqrt(sqr(dx2) + sqr(dy2));
  if (REALCOMPARE(d1, 0.0) = EQ) or (REALCOMPARE(d2, 0.0) = EQ) then
  begin
    ComputeAngle := -1.0; { undefined }
    Exit;
  end;
  dot := dx1 * dx2 + dy1 * dy2;
  cross := dx1 * dy2 - dy1 * dx2;
  ang := arctan2(abs(cross), dot);
  ComputeAngle := ang;
end;

{ Utility: distance from point (px,py) to line defined by (x1,y1)-(x2,y2) }
function PointToLineDist(px, py, x1, y1, x2, y2: real): real;
var
  dx, dy, linelen, num: real;
begin
  dx := x2 - x1;
  dy := y2 - y1;
  linelen := sqrt(sqr(dx) + sqr(dy));
  if REALCOMPARE(linelen, 0.0) = EQ then
  begin
    PointToLineDist := PointDist(px, py, x1, y1);
    Exit;
  end;
  num := abs(dy * px - dx * py + x2 * y1 - y2 * x1);
  PointToLineDist := num / linelen;
end;

{ ========== LIC Evaluation ========== }

procedure EvalLIC1;
var
  i: integer;
  d: real;
begin
  CMV[1] := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    d := PointDist(X[i], Y[i], X[i+1], Y[i+1]);
    if REALCOMPARE(d, PARAM_LENGTH1) = GT then
    begin
      CMV[1] := true;
      Exit;
    end;
  end;
end;

procedure EvalLIC2;
var
  i: integer;
begin
  CMV[2] := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if not FitsInCircle(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2], PARAM_RADIUS1) then
    begin
      CMV[2] := true;
      Exit;
    end;
  end;
end;

procedure EvalLIC3;
var
  i: integer;
  ang: real;
begin
  CMV[3] := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    ang := ComputeAngle(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]);
    if ang < 0 then continue; { undefined }
    if (REALCOMPARE(ang, MYPI - PARAM_EPSILON) = LT) or
       (REALCOMPARE(ang, MYPI + PARAM_EPSILON) = GT) then
    begin
      CMV[3] := true;
      Exit;
    end;
  end;
end;

procedure EvalLIC4;
var
  i: integer;
  area: real;
begin
  CMV[4] := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    area := TriangleArea(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]);
    if REALCOMPARE(area, PARAM_AREA1) = GT then
    begin
      CMV[4] := true;
      Exit;
    end;
  end;
end;

procedure EvalLIC5;
var
  i, j, q: integer;
  quads: array[1..4] of boolean;
  numQ: integer;
begin
  CMV[5] := false;
  for i := 1 to NUMPOINTS - PARAM_Q_PTS + 1 do
  begin
    for q := 1 to 4 do quads[q] := false;
    for j := i to i + PARAM_Q_PTS - 1 do
    begin
      q := GetQuadrant(X[j], Y[j]);
      quads[q] := true;
    end;
    numQ := 0;
    for q := 1 to 4 do
      if quads[q] then inc(numQ);
    if numQ > PARAM_QUADS then
    begin
      CMV[5] := true;
      Exit;
    end;
  end;
end;

procedure EvalLIC6;
var
  i: integer;
begin
  CMV[6] := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if REALCOMPARE(X[i+1] - X[i], 0.0) = LT then
    begin
      CMV[6] := true;
      Exit;
    end;
  end;
end;

procedure EvalLIC7;
var
  i, j: integer;
  d: real;
  firstX, firstY, lastX, lastY: real;
begin
  CMV[7] := false;
  if NUMPOINTS < 3 then Exit;
  for i := 1 to NUMPOINTS - PARAM_N_PTS + 1 do
  begin
    firstX := X[i];
    firstY := Y[i];
    lastX := X[i + PARAM_N_PTS - 1];
    lastY := Y[i + PARAM_N_PTS - 1];
    for j := i + 1 to i + PARAM_N_PTS - 2 do
    begin
      if (REALCOMPARE(firstX, lastX) = EQ) and (REALCOMPARE(firstY, lastY) = EQ) then
        d := PointDist(X[j], Y[j], firstX, firstY)
      else
        d := PointToLineDist(X[j], Y[j], firstX, firstY, lastX, lastY);
      if REALCOMPARE(d, PARAM_DIST) = GT then
      begin
        CMV[7] := true;
        Exit;
      end;
    end;
  end;
end;

procedure EvalLIC8;
var
  i, j: integer;
  d: real;
begin
  CMV[8] := false;
  if NUMPOINTS < 3 then Exit;
  for i := 1 to NUMPOINTS - PARAM_K_PTS - 1 do
  begin
    j := i + PARAM_K_PTS + 1;
    d := PointDist(X[i], Y[i], X[j], Y[j]);
    if REALCOMPARE(d, PARAM_LENGTH1) = GT then
    begin
      CMV[8] := true;
      Exit;
    end;
  end;
end;

procedure EvalLIC9;
var
  i, j, k: integer;
begin
  CMV[9] := false;
  if NUMPOINTS < 5 then Exit;
  for i := 1 to NUMPOINTS - PARAM_A_PTS - PARAM_B_PTS - 2 do
  begin
    j := i + PARAM_A_PTS + 1;
    k := j + PARAM_B_PTS + 1;
    if not FitsInCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAM_RADIUS1) then
    begin
      CMV[9] := true;
      Exit;
    end;
  end;
end;

procedure EvalLIC10;
var
  i, j, k: integer;
  ang: real;
begin
  CMV[10] := false;
  if NUMPOINTS < 5 then Exit;
  for i := 1 to NUMPOINTS - PARAM_C_PTS - PARAM_D_PTS - 2 do
  begin
    j := i + PARAM_C_PTS + 1;
    k := j + PARAM_D_PTS + 1;
    ang := ComputeAngle(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if ang < 0 then continue; { undefined }
    if (REALCOMPARE(ang, MYPI - PARAM_EPSILON) = LT) or
       (REALCOMPARE(ang, MYPI + PARAM_EPSILON) = GT) then
    begin
      CMV[10] := true;
      Exit;
    end;
  end;
end;

procedure EvalLIC11;
var
  i, j, k: integer;
  area: real;
begin
  CMV[11] := false;
  if NUMPOINTS < 5 then Exit;
  for i := 1 to NUMPOINTS - PARAM_E_PTS - PARAM_F_PTS - 2 do
  begin
    j := i + PARAM_E_PTS + 1;
    k := j + PARAM_F_PTS + 1;
    area := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if REALCOMPARE(area, PARAM_AREA1) = GT then
    begin
      CMV[11] := true;
      Exit;
    end;
  end;
end;

procedure EvalLIC12;
var
  i, j: integer;
begin
  CMV[12] := false;
  if NUMPOINTS < 3 then Exit;
  for i := 1 to NUMPOINTS - PARAM_G_PTS - 1 do
  begin
    j := i + PARAM_G_PTS + 1;
    if REALCOMPARE(X[j] - X[i], 0.0) = LT then
    begin
      CMV[12] := true;
      Exit;
    end;
  end;
end;

procedure EvalLIC13;
var
  i, j: integer;
  d: real;
  cond1, cond2: boolean;
begin
  CMV[13] := false;
  if NUMPOINTS < 3 then Exit;
  cond1 := false;
  cond2 := false;
  for i := 1 to NUMPOINTS - PARAM_K_PTS - 1 do
  begin
    j := i + PARAM_K_PTS + 1;
    d := PointDist(X[i], Y[i], X[j], Y[j]);
    if REALCOMPARE(d, PARAM_LENGTH1) = GT then
      cond1 := true;
    if REALCOMPARE(d, PARAM_LENGTH2) = LT then
      cond2 := true;
    if cond1 and cond2 then
    begin
      CMV[13] := true;
      Exit;
    end;
  end;
end;

procedure EvalLIC14;
var
  i, j, k: integer;
  cond1, cond2: boolean;
begin
  CMV[14] := false;
  if NUMPOINTS < 5 then Exit;
  cond1 := false;
  cond2 := false;
  for i := 1 to NUMPOINTS - PARAM_A_PTS - PARAM_B_PTS - 2 do
  begin
    j := i + PARAM_A_PTS + 1;
    k := j + PARAM_B_PTS + 1;
    if not FitsInCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAM_RADIUS1) then
      cond1 := true;
    if FitsInCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAM_RADIUS2) then
      cond2 := true;
    if cond1 and cond2 then
    begin
      CMV[14] := true;
      Exit;
    end;
  end;
end;

procedure EvalLIC15;
var
  i, j, k: integer;
  area: real;
  cond1, cond2: boolean;
begin
  CMV[15] := false;
  if NUMPOINTS < 5 then Exit;
  cond1 := false;
  cond2 := false;
  for i := 1 to NUMPOINTS - PARAM_E_PTS - PARAM_F_PTS - 2 do
  begin
    j := i + PARAM_E_PTS + 1;
    k := j + PARAM_F_PTS + 1;
    area := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if REALCOMPARE(area, PARAM_AREA1) = GT then
      cond1 := true;
    if REALCOMPARE(area, PARAM_AREA2) = LT then
      cond2 := true;
    if cond1 and cond2 then
    begin
      CMV[15] := true;
      Exit;
    end;
  end;
end;

{ Main DECIDE procedure }
procedure DECIDE;
var
  i, j: integer;
  allTrue: boolean;
begin
  { Evaluate all LICs }
  EvalLIC1;
  EvalLIC2;
  EvalLIC3;
  EvalLIC4;
  EvalLIC5;
  EvalLIC6;
  EvalLIC7;
  EvalLIC8;
  EvalLIC9;
  EvalLIC10;
  EvalLIC11;
  EvalLIC12;
  EvalLIC13;
  EvalLIC14;
  EvalLIC15;

  { Compute PUM off-diagonal elements }
  for i := 1 to 15 do
    for j := 1 to 15 do
    begin
      if i = j then continue; { diagonal is input }
      case LCM[i, j] of
        NOTUSED: PUM[i, j] := true;
        ANDD:    PUM[i, j] := CMV[i] and CMV[j];
        ORR:     PUM[i, j] := CMV[i] or CMV[j];
      end;
    end;

  { Compute FUV }
  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
    begin
      FUV[i] := true;
    end
    else
    begin
      allTrue := true;
      for j := 1 to 15 do
        if not PUM[i, j] then
        begin
          allTrue := false;
          break;
        end;
      FUV[i] := allTrue;
    end;
  end;

  { Compute LAUNCH }
  LAUNCH := true;
  for i := 1 to 15 do
    if not FUV[i] then
    begin
      LAUNCH := false;
      break;
    end;
end;

{ ========== JSON Parsing / Output ========== }

var
  inputStr: string;
  line: string;

function SkipWhitespace(const s: string; pos: integer): integer;
begin
  while (pos <= Length(s)) and (s[pos] in [' ', #9, #10, #13]) do
    inc(pos);
  SkipWhitespace := pos;
end;

function ParseNumber(const s: string; pos: integer; out val: real; out newPos: integer): boolean;
var
  startPos: integer;
  numStr: string;
begin
  pos := SkipWhitespace(s, pos);
  startPos := pos;
  if (pos <= Length(s)) and (s[pos] = '-') then inc(pos);
  while (pos <= Length(s)) and (s[pos] in ['0'..'9']) do inc(pos);
  if (pos <= Length(s)) and (s[pos] = '.') then
  begin
    inc(pos);
    while (pos <= Length(s)) and (s[pos] in ['0'..'9']) do inc(pos);
  end;
  if (pos <= Length(s)) and (s[pos] in ['e', 'E']) then
  begin
    inc(pos);
    if (pos <= Length(s)) and (s[pos] in ['+', '-']) then inc(pos);
    while (pos <= Length(s)) and (s[pos] in ['0'..'9']) do inc(pos);
  end;
  numStr := Copy(s, startPos, pos - startPos);
  val := StrToFloat(numStr);
  ParseNumber := true;
  newPos := pos;
end;

function ParseInteger(const s: string; pos: integer; out val: integer; out newPos: integer): boolean;
var
  r: real;
begin
  ParseInteger := ParseNumber(s, pos, r, newPos);
  val := Round(r);
end;

function ParseString(const s: string; pos: integer; out val: string; out newPos: integer): boolean;
begin
  pos := SkipWhitespace(s, pos);
  ParseString := false;
  val := '';
  if (pos > Length(s)) or (s[pos] <> '"') then Exit;
  inc(pos);
  while (pos <= Length(s)) and (s[pos] <> '"') do
  begin
    val := val + s[pos];
    inc(pos);
  end;
  if (pos <= Length(s)) and (s[pos] = '"') then
  begin
    inc(pos);
    ParseString := true;
  end;
  newPos := pos;
end;

function ParseBool(const s: string; pos: integer; out val: boolean; out newPos: integer): boolean;
begin
  pos := SkipWhitespace(s, pos);
  ParseBool := false;
  if (pos + 3 <= Length(s)) and (Copy(s, pos, 4) = 'true') then
  begin
    val := true;
    newPos := pos + 4;
    ParseBool := true;
  end
  else if (pos + 4 <= Length(s)) and (Copy(s, pos, 5) = 'false') then
  begin
    val := false;
    newPos := pos + 5;
    ParseBool := true;
  end;
end;

function ExpectChar(const s: string; pos: integer; c: char; out newPos: integer): boolean;
begin
  pos := SkipWhitespace(s, pos);
  if (pos <= Length(s)) and (s[pos] = c) then
  begin
    newPos := pos + 1;
    ExpectChar := true;
  end
  else
  begin
    newPos := pos;
    ExpectChar := false;
  end;
end;

function FindKey(const s: string; pos: integer; const key: string; out newPos: integer): integer;
{ Scan forward from pos to find "key": and return position after the colon }
var
  sKey: string;
  p: integer;
begin
  p := pos;
  while p <= Length(s) do
  begin
    p := SkipWhitespace(s, p);
    if (p <= Length(s)) and (s[p] = '"') then
    begin
      if ParseString(s, p, sKey, p) then
      begin
        p := SkipWhitespace(s, p);
        if (p <= Length(s)) and (s[p] = ':') then
        begin
          inc(p);
          if sKey = key then
          begin
            FindKey := p;
            newPos := p;
            Exit;
          end;
        end;
      end;
    end
    else
      inc(p);
  end;
  FindKey := 0;
  newPos := p;
end;

procedure ParseInput;
var
  pos, newPos, i, j: integer;
  r: real;
  bVal: boolean;
  sVal: string;
begin
  { Find numpoints }
  pos := FindKey(inputStr, 1, 'numpoints', newPos);
  ParseInteger(inputStr, newPos, NUMPOINTS, newPos);

  { Find x array }
  pos := FindKey(inputStr, 1, 'x', newPos);
  newPos := pos;
  ExpectChar(inputStr, newPos, '[', newPos);
  for i := 1 to NUMPOINTS do
  begin
    newPos := SkipWhitespace(inputStr, newPos);
    ParseNumber(inputStr, newPos, r, newPos);
    X[i] := r;
    newPos := SkipWhitespace(inputStr, newPos);
    if (newPos <= Length(inputStr)) and (inputStr[newPos] = ',') then inc(newPos);
  end;

  { Find y array }
  pos := FindKey(inputStr, 1, 'y', newPos);
  { Need to be careful: 'y' might match inside other keys. Search from a fresh position. }
  { Let's do a more targeted search }
  newPos := pos;
  ExpectChar(inputStr, newPos, '[', newPos);
  for i := 1 to NUMPOINTS do
  begin
    newPos := SkipWhitespace(inputStr, newPos);
    ParseNumber(inputStr, newPos, r, newPos);
    Y[i] := r;
    newPos := SkipWhitespace(inputStr, newPos);
    if (newPos <= Length(inputStr)) and (inputStr[newPos] = ',') then inc(newPos);
  end;

  { Find parameters object }
  pos := FindKey(inputStr, 1, 'parameters', newPos);
  newPos := pos;

  { Parse each parameter }
  pos := FindKey(inputStr, newPos, 'LENGTH1', newPos);
  ParseNumber(inputStr, newPos, PARAM_LENGTH1, newPos);

  pos := FindKey(inputStr, newPos, 'RADIUS1', newPos);
  ParseNumber(inputStr, newPos, PARAM_RADIUS1, newPos);

  pos := FindKey(inputStr, newPos, 'EPSILON', newPos);
  ParseNumber(inputStr, newPos, PARAM_EPSILON, newPos);

  pos := FindKey(inputStr, newPos, 'AREA1', newPos);
  ParseNumber(inputStr, newPos, PARAM_AREA1, newPos);

  pos := FindKey(inputStr, newPos, 'Q_PTS', newPos);
  ParseInteger(inputStr, newPos, PARAM_Q_PTS, newPos);

  pos := FindKey(inputStr, newPos, 'QUADS', newPos);
  ParseInteger(inputStr, newPos, PARAM_QUADS, newPos);

  pos := FindKey(inputStr, newPos, 'DIST', newPos);
  ParseNumber(inputStr, newPos, PARAM_DIST, newPos);

  pos := FindKey(inputStr, newPos, 'N_PTS', newPos);
  ParseInteger(inputStr, newPos, PARAM_N_PTS, newPos);

  pos := FindKey(inputStr, newPos, 'K_PTS', newPos);
  ParseInteger(inputStr, newPos, PARAM_K_PTS, newPos);

  pos := FindKey(inputStr, newPos, 'A_PTS', newPos);
  ParseInteger(inputStr, newPos, PARAM_A_PTS, newPos);

  pos := FindKey(inputStr, newPos, 'B_PTS', newPos);
  ParseInteger(inputStr, newPos, PARAM_B_PTS, newPos);

  pos := FindKey(inputStr, newPos, 'C_PTS', newPos);
  ParseInteger(inputStr, newPos, PARAM_C_PTS, newPos);

  pos := FindKey(inputStr, newPos, 'D_PTS', newPos);
  ParseInteger(inputStr, newPos, PARAM_D_PTS, newPos);

  pos := FindKey(inputStr, newPos, 'E_PTS', newPos);
  ParseInteger(inputStr, newPos, PARAM_E_PTS, newPos);

  pos := FindKey(inputStr, newPos, 'F_PTS', newPos);
  ParseInteger(inputStr, newPos, PARAM_F_PTS, newPos);

  pos := FindKey(inputStr, newPos, 'G_PTS', newPos);
  ParseInteger(inputStr, newPos, PARAM_G_PTS, newPos);

  pos := FindKey(inputStr, newPos, 'LENGTH2', newPos);
