  pos := FindKey(inputStr, newPos, 'RADIUS2', newPos);
  ParseNumber(inputStr, newPos, PARAM_RADIUS2, newPos);

  pos := FindKey(inputStr, newPos, 'AREA2', newPos);
  ParseNumber(inputStr, newPos, PARAM_AREA2, newPos);

  { Find lcm array }
  pos := FindKey(inputStr, 1, 'lcm', newPos);
  newPos := pos;
  ExpectChar(inputStr, newPos, '[', newPos);
  for i := 1 to 15 do
  begin
    newPos := SkipWhitespace(inputStr, newPos);
    ExpectChar(inputStr, newPos, '[', newPos);
    for j := 1 to 15 do
    begin
      newPos := SkipWhitespace(inputStr, newPos);
      ParseString(inputStr, newPos, sVal, newPos);
      if sVal = 'NOTUSED' then
        LCM[i, j] := NOTUSED
      else if sVal = 'ORR' then
        LCM[i, j] := ORR
      else if sVal = 'ANDD' then
        LCM[i, j] := ANDD;
      newPos := SkipWhitespace(inputStr, newPos);
      if (newPos <= Length(inputStr)) and (inputStr[newPos] = ',') then inc(newPos);
    end;
    ExpectChar(inputStr, newPos, ']', newPos);
    newPos := SkipWhitespace(inputStr, newPos);
    if (newPos <= Length(inputStr)) and (inputStr[newPos] = ',') then inc(newPos);
  end;

  { Find pum_diag array }
  pos := FindKey(inputStr, 1, 'pum_diag', newPos);
