  for i := 1 to 15 do
  begin
    newPos := SkipWhitespace(inputStr, newPos);
    ParseBool(inputStr, newPos, bVal, newPos);
    PUM[i, i] := bVal;
    newPos := SkipWhitespace(inputStr, newPos);
    if (newPos <= Length(inputStr)) and (inputStr[newPos] = ',') then inc(newPos);
  end;
end;

function BoolToJSON(b: boolean): string;
begin
  if b then BoolToJSON := 'true' else BoolToJSON := 'false';
end;

procedure WriteOutput;
var
  i, j: integer;
begin
  Write('{"cmv": [');
  for i := 1 to 15 do
  begin
    Write(BoolToJSON(CMV[i]));
    if i < 15 then Write(', ');
  end;
  Write('], "pum": [');
  for i := 1 to 15 do
  begin
    Write('[');
    for j := 1 to 15 do
    begin
      Write(BoolToJSON(PUM[i, j]));
      if j < 15 then Write(', ');
    end;
    Write(']');
    if i < 15 then Write(', ');
  end;
  Write('], "fuv": [');
  for i := 1 to 15 do
  begin
    Write(BoolToJSON(FUV[i]));
    if i < 15 then Write(', ');
  end;
  Write('], "launch": ');
  Write(BoolToJSON(LAUNCH));
  WriteLn('}');
end;

